'use strict';



window.addEventListener('scroll', () => {
  const el = document.getElementById('progress');
  const d  = document.documentElement;
  el.style.width = Math.min(100,
    (d.scrollTop || document.body.scrollTop) /
    (d.scrollHeight - d.clientHeight) * 100) + '%';
});

/* ── PREPROCESSING  (Cell 9 — TextPreprocessor.clean) ────────── */
const SW = new Set([
  'i','me','my','myself','we','our','ours','ourselves','you','your','yours',
  'yourself','yourselves','he','him','his','himself','she','her','hers',
  'herself','it','its','itself','they','them','their','theirs','themselves',
  'what','which','who','whom','this','that','these','those','am','is','are',
  'was','were','be','been','being','have','has','had','having','do','does',
  'did','doing','a','an','the','and','or','as','at','by','for','of','to',
  'in','if','on','so','up','us','via','per','re','vs','etc',
  'would','could','should','may','might','will','shall','can',
  'with','from','about','against','between','into','through',
  'during','before','after','above','below','out','off','over','under',
  'again','further','then','once','here','there','when','where','why','how',
  'some','such','than','too','very','just','because','while','although',
  'though','since','until','unless','also','even','like','same','own','only',
]);
['not','no','never','but','however','neither','nor','all','any'].forEach(w => SW.delete(w));

function stem(w) {
  if (w.length <= 3) return w;
  for (const s of ['tion','tions','ness','ment','ments','able','ible',
                   'ful','less','ous','ive','ize','ise','ing','ed','ly','er','al'])
    if (w.endsWith(s) && w.length - s.length >= 3) return w.slice(0, -s.length);
  return w;
}

function cleanText(text) {
  text = String(text).toLowerCase();
  text = text.replace(/https?\S+|www\S+/g, ' ');
  text = text.replace(/\d+/g, ' ');
  text = text.replace(/[^\w\s]/g, ' ');
  text = text.replace(/\s+/g, ' ').trim();
  return text.split(' ').filter(t => t.length > 2 && !SW.has(t)).map(stem).join(' ');
}

